mapper.select:
SELECT DISTINCT m.USER_ID, m.USER_NAME FROM COURSE c JOIN MEMBER m ON c.INSTR_USER_ID = m.USER_ID LEFT JOIN SUBJECT s ON c.SUBJ_ID = s.SUBJ_ID LEFT JOIN SUBJECT_CLASSIFICATION sc ON s.SUBJ_CL_ID = sc.SUBJ_CL_ID WHERE c.OPNN_YN = 'Y'
AND sc.SUBJ_CL_ID = #{subjClId}
ORDER BY m.USER_NAME ASC
